            <div class="clearfix grpelem" id="u29030"><!-- group -->
                <div class="clearfix grpelem" id="pu29024-4"><!-- column -->
                    <!-- m_editable region-id="editable-static-tag-U29024-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
                    <div class="clearfix colelem" id="u29024-4" data-muse-uid="U29024" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedCenter"><!-- content -->
                        <h1 id="u29024-2"><span id="u29024">О жилом комплексе Позитив</span></h1>
                    </div>
                    <!-- /m_editable -->
                    <!-- m_editable region-id="editable-static-tag-U23136-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
                    <div class="clearfix colelem" id="u23136-4" data-muse-uid="U23136" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedCenter"><!-- content -->
                        <p id="u23136-2"><span id="u23136">«Позитив» – это уникальная новостройка в Румянцево. Жилой комплекс представляет собой квартальную застройку многоэтажных домов (от 16 до 25 этажей) новой инновационной серии ДОММОС. Большой и светлый двор станет приятным местом отдыха для будущих жителей. С помощью ландшафтного дизайна, внутреннее пространство превращается в парк с зонами для отдыха, детскими и спортивными площадками! Сочетание размеренной загородной жизни и ритма современного города отражают теплые тона фасадов зданий с яркими акцентами на торцах домов. Комфорт во всем - залог позитивного взгляда на жизнь!</span></p>
                    </div>
                    <!-- /m_editable -->
                </div>
            </div>
        </div>
        <div class="clearfix grpelem shared_content" id="pu23139" data-content-guid="pu23139_content"><!-- column -->
            <div class="museBGSize colelem shared_content" id="u23139" data-sizePolicy="fluidWidth" data-pintopage="page_fixedLeft" data-content-guid="u23139_content"><!-- simple frame --></div>
            <div class="browser_width colelem" id="u84897-bw">
                <div class="museBGSize" id="u84897"><!-- group -->
                    <div class="clearfix" id="u84897_align_to_page">
                        <div class="clearfix grpelem" id="u112247"><!-- group -->
                            <div class="clearfix grpelem" id="pu84971-7"><!-- column -->
                                <!-- m_editable region-id="editable-static-tag-U84971-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
                                <div class="clearfix colelem" id="u84971-7" data-muse-uid="U84971" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedLeft"><!-- content -->
                                    <p id="u84971-5" class="shared_content" data-content-guid="u84971-5_content"><span id="u84971">клинкерная плитка</span><span id="u84971-3"><br/></span><span id="u84971-4">немецкого качества</span></p>
                                </div>
                                <!-- /m_editable -->
                                <!-- m_editable region-id="editable-static-tag-U85144-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
                                <div class="clearfix colelem" id="u85144-4" data-muse-uid="U85144" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedLeft"><!-- content -->
                                    <p id="u85144-2" class="shared_content" data-content-guid="u85144-2_content"><span id="u85144">фасады дома облицованы качественной немецкой клинкерной плиткой, которая изготавливается из натуральной глины с добавками минеральных красителей</span></p>
                                </div>
                                <!-- /m_editable -->
                            </div>
                        </div>
                    </div>
                </div>
            </div>
            <div class="museBGSize colelem shared_content" id="u29060" data-sizePolicy="fluidWidth" data-pintopage="page_fixedLeft" data-content-guid="u29060_content"><!-- simple frame --></div>
            <div class="museBGSize colelem shared_content" id="u29160" data-sizePolicy="fluidWidth" data-pintopage="page_fixedLeft" data-content-guid="u29160_content"><!-- simple frame --></div>
