            <!-- m_editable region-id="editable-static-tag-U29020-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
            <div class="clearfix colelem shared_content" id="u29020-4" data-muse-uid="U29020" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedCenter" data-leftAdjustmentDoneBy="pu29020-4" data-content-guid="u29020-4_content"><!-- content -->
                <h2 id="u29020-2" class="shared_content" data-content-guid="u29020-2_content"><span id="u29020">Рядом метро и удобная транспортная развязка</span></h2>
            </div>
            <!-- /m_editable -->
            <!-- m_editable region-id="editable-static-tag-U23150-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
            <div class="o-proekte clearfix colelem shared_content" id="u23150-8" data-muse-uid="U23150" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedCenter" data-leftAdjustmentDoneBy="pu29020-4" data-content-guid="u23150-8_content"><!-- content -->
                <p id="u23150-6" class="shared_content" data-content-guid="u23150-6_content"><span class="main-text-Character-Style" id="u23150">Еще один плюс жилого комплекса «Позитив» - </span><span id="u23150-4"><a class="nonblock" href="infrastruktura_rumyantsevo.html" data-href="page:U8602"><span class="main-text-Character-Style" id="u23150-2">транспортная доступность</span></a></span><span class="main-text-Character-Style" id="u23150-5">. Он находится всего в 3 км от МКАД по Киевскому шоссе. Благодаря удачному расположению между станциями метро «Румянцево», «Саларьево», и ж/д станцией «Новопеределкино» можно добраться до многих точек города можно без пересадок, и быть в центре Москвы всего за 25-30 мин.</span></p>
            </div>
            <!-- /m_editable -->
            <!-- m_editable region-id="editable-static-tag-U22910-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
            <a class="clearfix colelem x777" id="u22910-4" data-muse-uid="U22910" data-muse-type="txt_frame" data-IBE-flags="txtStyleSrc" data-sizePolicy="fixed" data-pintopage="page_fixedCenter" data-leftAdjustmentDoneBy="pu29020-4"  href="/hod-stroitelstva.html"><!-- content -->
                <h4 id="u22910-2" class="shared_content x888" data-content-guid="u22910-2_content">Посмотрите на ход строительства объекта!</h4>
            </a>
            <!-- /m_editable -->
            <!-- m_editable region-id="editable-static-tag-U671306-BP_infinity" template="o_proekte_gk_pozitiv.html" data-type="html" data-ice-options="disableImageResize,link,txtStyleTarget" -->
